config.grammar:
format {
  name = "Name Format"
  description = "Simple name CSV format"
  start-element = "File"
  target-namespace = "Names"

  elements = [
    {
      name = "File"
      type = "Sequence"
      references = [
        {
          name = "Records"
          max-occurs = "unlimited"
          referenced-element = "Record"
        }
      ]
    },
    {
      name = "Record"
      type = "Separated"
      separator = ","
      terminator = "\n"

      mapping = {
        message = "Record"
        element = "NAME_IN"
      }

      fields = [
        {
          name = "name"
          type = "String"
        }
      ]
    }
  ]
}
